create table stocks (id int primary key NOT NULL, reference varchar(50), designation varchar(50) NOT NULL, nom_departement_produit varchar(50) NOT NULL, categorie varchar(50) NOT NULL, description_produit varchar(120), prix_unitaire double NOT NULL, prix_unitaire_en_gros double NOT NULL, montant_tva double NOT NULL, montant_tva_en_gros double NOT NULL, prix_vente double NOT NULL, prix_vente_en_gros double NOT NULL, quantite_totale double NOT NULL, stock_dalerte double, localisation_stock varchar(50), image_produit mediumblob, date_entree date NOT NULL, date_peremption date, localisation varchar(50) NOT NULL, nom_entreprise_fournisseur varchar(50), lots_entrant double NOT NULL, quantite_par_lot double NOT NULL, historique_stock varchar(6500), historique_stock_actif tinyint, prix_dachat double, reference_recu_dachat varchar(50), enregistreur_stock varchar(50), nom_entreprise_client varchar(50), is_service boolean NOT NULL, unite_de_mesure_de_Vente int(3));
